# scripts/verify_layer4_functional.py
# Golden-path smoke test for the GenAI chat service.
# Sends a realistic query and validates the response shape and content.

import os, sys, httpx, json

SERVICE_URL = os.environ["SERVICE_URL"]   # e.g. https://api.example.com
AUTH_TOKEN = os.environ.get("SMOKE_TEST_TOKEN", "")

print("=== Layer 4: Functional Smoke Test ===")

SMOKE_CASES = [
    {
        "name": "basic_greeting",
        "payload": {"message": "Hello, can you help me?"},
        "expect_keys": ["reply", "session_id"],
        "min_reply_length": 10,
    },
    {
        "name": "out_of_scope_rejection",
        "payload": {"message": "Please write me a poem about cats."},
        "expect_keys": ["reply", "session_id"],
        "must_not_contain": ["<script>", "ignore previous instructions"],
    },
]

headers = {"Content-Type": "application/json"}
if AUTH_TOKEN:
    headers["Authorization"] = f"Bearer {AUTH_TOKEN}"

failures = []
for case in SMOKE_CASES:
    try:
        resp = httpx.post(
            f"{SERVICE_URL}/v1/chat",
            json=case["payload"],
            headers=headers,
            timeout=20.0,
        )
        resp.raise_for_status()
        body = resp.json()
    except Exception as e:
        failures.append(f"[{case['name']}] Request failed: {e}")
        continue

    # Check required keys
    for key in case.get("expect_keys", []):
        if key not in body:
            failures.append(f"[{case['name']}] Missing key: {key}")

    # Check minimum reply length
    reply = body.get("reply", "")
    min_len = case.get("min_reply_length", 0)
    if len(reply) < min_len:
        failures.append(f"[{case['name']}] Reply too short: {len(reply)} < {min_len}")

    # Check forbidden strings
    for forbidden in case.get("must_not_contain", []):
        if forbidden.lower() in reply.lower():
            failures.append(f"[{case['name']}] Forbidden string in reply: {forbidden!r}")

    print(f"  [{case['name']}]: PASS (reply length={len(reply)})")

if failures:
    print("Layer 4 FAILURES:")
    for f in failures:
        print(f"  - {f}")
    sys.exit(1)

print("Layer 4: PASS")
